create table players (
    player_id           number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    team_id             number not null enable,
    jersey_number       number(2, 0) not null enable,
    first_name          varchar2(60 byte) not null enable,
    last_name           varchar2(60 byte) not null enable,
    player_position     varchar2(20 byte) not null enable,
    birth_date          date,
    height_cm           number(5, 2),
    weight_kg           number(5, 2),
    roster_status       varchar2(20 byte) default 'ACTIVE' not null enable,
    contract_start_date date,
    contract_end_date   date
);

alter table players
    add constraint players_pk primary key ( player_id )
        using index enable;

alter table players
    add constraint players_position_ck
        check ( player_position in ( 'POINT_GUARD', 'SHOOTING_GUARD', 'SMALL_FORWARD', 'POWER_FORWARD', 'CENTER' ) ) enable;

alter table players
    add constraint players_status_ck
        check ( roster_status in ( 'ACTIVE', 'INJURED', 'G_LEAGUE', 'RELEASED' ) ) enable;

alter table players
    add constraint players_team_jersey_uk unique ( team_id,
                                                   jersey_number )
        using index enable;

